import { useQuery, useQueryClient } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Loader2, RefreshCw, Search, MapPin, CheckCircle2, AlertCircle, Trash2, Clock } from "lucide-react";
import { toast } from "sonner";
import { useState } from "react";

interface SearchRecord {
  id: string;
  country: string | null;
  city: string | null;
  category: string | null;
  keyword: string | null;
  total_discovered: number;
  duplicates_filtered: number;
  imported_count: number;
  failed_count: number;
  results: any[];
  search_params: any;
  created_at: string;
}

const CATEGORY_LABELS: Record<string, string> = {
  landmark: "🏛️ 名胜古迹",
  historic_building: "🏰 历史建筑餐厅",
  celebrity: "⭐ 名人餐厅",
  michelin: "🌟 米其林",
  street_landmark: "🗺️ 百年老店",
  asian: "🌏 亚洲菜",
  european: "🇪🇺 欧洲菜",
  latin_american: "🌎 拉丁美洲",
  african: "🌍 非洲菜",
  middle_eastern: "🕌 中东菜",
  american: "🇺🇸 美式餐",
};

export default function SearchHistoryPanel() {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const { data: records, isLoading } = useQuery({
    queryKey: ["search-history"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("discovery_search_history")
        .select("*")
        .order("created_at", { ascending: false })
        .limit(100);
      if (error) throw error;
      return data as SearchRecord[];
    },
  });

  const handleDelete = async (id: string) => {
    const { error } = await supabase.from("discovery_search_history").delete().eq("id", id);
    if (error) {
      toast.error(t("toast.deleteFailed"));
    } else {
      toast.success(t("common.deleted"));
      queryClient.invalidateQueries({ queryKey: ["search-history"] });
    }
  };

  const handleClearAll = async () => {
    if (!window.confirm(t("toast.confirmClearAll"))) return;
    const { error } = await supabase.from("discovery_search_history").delete().neq("id", "00000000-0000-0000-0000-000000000000");
    if (error) {
      toast.error(t("toast.clearFailed"));
    } else {
      toast.success(t("toast.cleared"));
      queryClient.invalidateQueries({ queryKey: ["search-history"] });
    }
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="flex items-center justify-center py-10">
          <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
        </CardContent>
      </Card>
    );
  }

  if (!records || records.length === 0) {
    return (
      <Card>
        <CardContent className="flex flex-col items-center py-10 gap-2">
          <Clock className="h-8 w-8 text-muted-foreground" />
          <p className="text-sm text-muted-foreground">暂无搜索记录</p>
          <p className="text-xs text-muted-foreground">在「手动搜索」标签页执行搜索后，记录会自动保存到这里</p>
        </CardContent>
      </Card>
    );
  }

  // Aggregate stats
  const totalSearches = records.length;
  const totalDiscovered = records.reduce((s, r) => s + (r.total_discovered || 0), 0);
  const totalImported = records.reduce((s, r) => s + (r.imported_count || 0), 0);
  const countryCounts = records.reduce((acc, r) => {
    if (r.country) acc[r.country] = (acc[r.country] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  return (
    <div className="space-y-4">
      {/* Summary */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
        <SummaryCard label="总搜索次数" value={totalSearches} />
        <SummaryCard label="总发现数" value={totalDiscovered} />
        <SummaryCard label="总导入数" value={totalImported} />
        <SummaryCard label="覆盖国家" value={Object.keys(countryCounts).length} />
      </div>

      {/* Actions */}
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-medium">搜索记录 ({records.length})</h3>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => queryClient.invalidateQueries({ queryKey: ["search-history"] })}>
            <RefreshCw className="mr-1 h-3 w-3" /> 刷新
          </Button>
          <Button variant="ghost" size="sm" onClick={handleClearAll} className="text-destructive">
            <Trash2 className="mr-1 h-3 w-3" /> 清空
          </Button>
        </div>
      </div>

      {/* Records */}
      <Card>
        <CardContent className="p-0">
          <ScrollArea className="h-[55vh]">
            <div className="divide-y">
              {records.map(record => {
                const isExpanded = expandedId === record.id;
                const results = Array.isArray(record.results) ? record.results : [];
                return (
                  <div key={record.id} className="px-4 py-3">
                    <div
                      className="flex items-center gap-3 cursor-pointer hover:opacity-80"
                      onClick={() => setExpandedId(isExpanded ? null : record.id)}
                    >
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 text-sm">
                          <Search className="h-3.5 w-3.5 text-muted-foreground flex-shrink-0" />
                          <span className="font-medium">
                            {record.country || "?"}
                            {record.city ? ` / ${record.city}` : " / 全部城市"}
                          </span>
                          <Badge variant="outline" className="text-[9px] h-4">
                            {CATEGORY_LABELS[record.category || ""] || record.category || "未知"}
                          </Badge>
                          {record.keyword && (
                            <Badge variant="secondary" className="text-[9px] h-4">
                              "{record.keyword}"
                            </Badge>
                          )}
                        </div>
                        <div className="flex items-center gap-3 mt-1 text-[10px] text-muted-foreground">
                          <span className="flex items-center gap-0.5">
                            <CheckCircle2 className="h-3 w-3 text-emerald-500" />
                            发现 {record.total_discovered}
                          </span>
                          <span className="flex items-center gap-0.5">
                            <AlertCircle className="h-3 w-3 text-yellow-500" />
                            重复 {record.duplicates_filtered}
                          </span>
                          {record.imported_count > 0 && (
                            <span className="text-emerald-600 font-medium">
                              已导入 {record.imported_count}
                            </span>
                          )}
                          <span className="text-muted-foreground/50">
                            {new Date(record.created_at).toLocaleString("zh-CN", {
                              month: "2-digit", day: "2-digit",
                              hour: "2-digit", minute: "2-digit",
                            })}
                          </span>
                        </div>
                      </div>
                      <Button
                        variant="ghost" size="icon" className="h-6 w-6"
                        onClick={(e) => { e.stopPropagation(); handleDelete(record.id); }}
                      >
                        <Trash2 className="h-3 w-3 text-muted-foreground" />
                      </Button>
                    </div>

                    {/* Expanded: show discovered items */}
                    {isExpanded && results.length > 0 && (
                      <div className="mt-2 ml-6 space-y-1 border-l-2 border-muted pl-3">
                        {results.map((r: any, i: number) => (
                          <div key={i} className="flex items-center gap-2 text-xs">
                            {r.verified !== false ? (
                              <CheckCircle2 className="h-3 w-3 text-emerald-500 flex-shrink-0" />
                            ) : (
                              <AlertCircle className="h-3 w-3 text-yellow-500 flex-shrink-0" />
                            )}
                            <span className="truncate font-medium">{r.name}</span>
                            {r.place_id && (
                              <Badge variant="outline" className="text-[8px] h-3 px-0.5 border-emerald-300 text-emerald-600">PID</Badge>
                            )}
                            <span className="text-muted-foreground truncate flex items-center gap-0.5">
                              <MapPin className="h-2.5 w-2.5" />{r.address}
                            </span>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </ScrollArea>
        </CardContent>
      </Card>
    </div>
  );
}

function SummaryCard({ label, value }: { label: string; value: number }) {
  return (
    <Card>
      <CardContent className="pt-3 pb-2 px-3 text-center">
        <div className="text-xl font-bold text-foreground">{value}</div>
        <div className="text-[10px] text-muted-foreground">{label}</div>
      </CardContent>
    </Card>
  );
}
