import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Loader2, Import, CheckCircle2, AlertCircle, Search } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

const COUNTRIES = [
  { code: "Portugal", label: "🇵🇹 葡萄牙" },
  { code: "Spain", label: "🇪🇸 西班牙" },
  { code: "France", label: "🇫🇷 法国" },
  { code: "Germany", label: "🇩🇪 德国" },
  { code: "Italy", label: "🇮🇹 意大利" },
  { code: "United Kingdom", label: "🇬🇧 英国" },
  { code: "Netherlands", label: "🇳🇱 荷兰" },
  { code: "Japan", label: "🇯🇵 日本" },
  { code: "South Korea", label: "🇰🇷 韩国" },
  { code: "United States", label: "🇺🇸 美国" },
];

interface ImportResult {
  success: boolean;
  country?: string;
  total_found?: number;
  imported?: number;
  skipped?: number;
  errors?: string[];
  dry_run?: boolean;
  award_breakdown?: Record<string, number>;
  sample?: Array<{ name: string; city: string; michelin_stars: string; type_en: string[] }>;
  error?: string;
}

interface FindUrlResult {
  success: boolean;
  dry_run?: boolean;
  processed?: number;
  found?: number;
  not_found?: number;
  remaining?: number;
  results?: Array<{ id: string; name: string; city: string; michelin_url: string | null; score: number; updated: boolean; reason?: string }>;
  error?: string;
}

export default function MichelinImportPanel() {
  const { toast } = useToast();
  const [country, setCountry] = useState("Spain");
  const [city, setCity] = useState("Madrid");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ImportResult | null>(null);

  // Find URLs state
  const [findLoading, setFindLoading] = useState(false);
  const [findResult, setFindResult] = useState<FindUrlResult | null>(null);
  const [findCountry, setFindCountry] = useState("all");
  const [findLimit, setFindLimit] = useState("10");

  const handleImport = async (dryRun: boolean) => {
    setLoading(true);
    setResult(null);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error("Not authenticated");

      const res = await supabase.functions.invoke("import-michelin-restaurants", {
        body: { country, city: city.trim() || null, dry_run: dryRun },
      });

      if (res.error) throw res.error;
      setResult(res.data as ImportResult);

      if (!dryRun && res.data?.imported > 0) {
        toast({
          title: `成功导入 ${res.data.imported} 家米其林餐厅`,
          description: `${country} - 跳过 ${res.data.skipped} 家重复`,
        });
      }
    } catch (err: any) {
      toast({ title: "导入失败", description: err.message, variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const handleFindUrls = async (dryRun: boolean) => {
    setFindLoading(true);
    setFindResult(null);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error("Not authenticated");

      const body: any = { limit: parseInt(findLimit), dry_run: dryRun };
      if (findCountry !== "all") body.country = findCountry;

      const res = await supabase.functions.invoke("find-michelin-urls", { body });
      if (res.error) throw res.error;
      setFindResult(res.data as FindUrlResult);

      if (!dryRun && res.data?.found > 0) {
        toast({
          title: `已补充 ${res.data.found} 个米其林指南网址`,
          description: `剩余 ${res.data.remaining} 家待查找`,
        });
      }
    } catch (err: any) {
      toast({ title: "查找失败", description: err.message, variant: "destructive" });
    } finally {
      setFindLoading(false);
    }
  };

  return (
    <div className="space-y-4">
      {/* Original Import Panel */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Import className="h-5 w-5" />
            米其林餐厅批量导入
          </CardTitle>
          <CardDescription>
            从 GitHub 米其林数据集 (ngshiheng/michelin-my-maps) 批量导入 18,000+ 餐厅数据，包含1-3星、必比登推介等
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center gap-3 flex-wrap">
            <Select value={country} onValueChange={setCountry}>
              <SelectTrigger className="w-[200px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {COUNTRIES.map(c => (
                  <SelectItem key={c.code} value={c.code}>{c.label}</SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Input 
              placeholder="城市（可选，如 Madrid）" 
              value={city} 
              onChange={e => setCity(e.target.value)} 
              className="w-[200px]" 
            />
            <Button variant="outline" onClick={() => handleImport(true)} disabled={loading}>
              {loading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : null}
              预览
            </Button>
            <Button onClick={() => handleImport(false)} disabled={loading}>
              {loading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <Import className="h-4 w-4 mr-1" />}
              导入
            </Button>
          </div>

          {result && (
            <div className="space-y-3 p-4 rounded-lg border bg-muted/30">
              {result.error ? (
                <div className="flex items-center gap-2 text-destructive">
                  <AlertCircle className="h-4 w-4" />
                  <span>{result.error}</span>
                </div>
              ) : (
                <>
                  <div className="flex items-center gap-2">
                    <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                    <span className="font-medium">
                      {result.dry_run ? '预览结果' : '导入完成'} - {result.country}
                    </span>
                  </div>
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 text-sm">
                    <div className="p-2 rounded bg-background border">
                      <div className="text-muted-foreground text-xs">总计发现</div>
                      <div className="font-bold text-lg">{result.total_found}</div>
                    </div>
                    {!result.dry_run && (
                      <>
                        <div className="p-2 rounded bg-background border">
                          <div className="text-muted-foreground text-xs">已导入</div>
                          <div className="font-bold text-lg text-emerald-600">{result.imported}</div>
                        </div>
                        <div className="p-2 rounded bg-background border">
                          <div className="text-muted-foreground text-xs">跳过(重复)</div>
                          <div className="font-bold text-lg text-amber-600">{result.skipped}</div>
                        </div>
                      </>
                    )}
                  </div>

                  {result.award_breakdown && (
                    <div className="flex flex-wrap gap-2">
                      {result.award_breakdown.three_stars > 0 && (
                        <Badge className="bg-yellow-500/15 text-yellow-700 border-yellow-500/30">⭐⭐⭐ 三星 {result.award_breakdown.three_stars}</Badge>
                      )}
                      {result.award_breakdown.two_stars > 0 && (
                        <Badge className="bg-yellow-500/15 text-yellow-700 border-yellow-500/30">⭐⭐ 二星 {result.award_breakdown.two_stars}</Badge>
                      )}
                      {result.award_breakdown.one_star > 0 && (
                        <Badge className="bg-yellow-500/15 text-yellow-700 border-yellow-500/30">⭐ 一星 {result.award_breakdown.one_star}</Badge>
                      )}
                      {result.award_breakdown.bib_gourmand > 0 && (
                        <Badge className="bg-red-500/15 text-red-700 border-red-500/30">🍽️ 必比登 {result.award_breakdown.bib_gourmand}</Badge>
                      )}
                      {result.award_breakdown.selected > 0 && (
                        <Badge className="bg-orange-500/15 text-orange-700 border-orange-500/30">🌟 入选 {result.award_breakdown.selected}</Badge>
                      )}
                    </div>
                  )}

                  {result.sample && result.sample.length > 0 && (
                    <div className="space-y-1">
                      <div className="text-xs text-muted-foreground font-medium">示例:</div>
                      {result.sample.map((r, i) => (
                        <div key={i} className="text-sm flex items-center gap-2">
                          <span className="font-medium">{r.name}</span>
                          <span className="text-muted-foreground text-xs">{r.city}</span>
                          <Badge variant="outline" className="text-[10px]">{r.michelin_stars}</Badge>
                        </div>
                      ))}
                    </div>
                  )}

                  {result.errors && result.errors.length > 0 && (
                    <div className="space-y-1">
                      <div className="text-xs text-destructive font-medium">错误 ({result.errors.length}):</div>
                      {result.errors.slice(0, 5).map((err, i) => (
                        <div key={i} className="text-xs text-destructive">{err}</div>
                      ))}
                    </div>
                  )}
                </>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Find Michelin URLs Panel */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Search className="h-5 w-5" />
            补充米其林指南网址
          </CardTitle>
          <CardDescription>
            查找缺少米其林指南网址的餐厅，通过 Firecrawl 搜索米其林官网自动补充 URL
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center gap-3 flex-wrap">
            <Select value={findCountry} onValueChange={setFindCountry}>
              <SelectTrigger className="w-[200px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">🌍 全部国家</SelectItem>
                {COUNTRIES.map(c => (
                  <SelectItem key={c.code} value={c.code}>{c.label}</SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Input
              type="number"
              placeholder="数量"
              value={findLimit}
              onChange={e => setFindLimit(e.target.value)}
              className="w-[100px]"
              min={1}
              max={50}
            />
            <Button variant="outline" onClick={() => handleFindUrls(true)} disabled={findLoading}>
              {findLoading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : null}
              预览
            </Button>
            <Button onClick={() => handleFindUrls(false)} disabled={findLoading}>
              {findLoading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <Search className="h-4 w-4 mr-1" />}
              查找并补充
            </Button>
          </div>

          {findResult && (
            <div className="space-y-3 p-4 rounded-lg border bg-muted/30">
              {findResult.error ? (
                <div className="flex items-center gap-2 text-destructive">
                  <AlertCircle className="h-4 w-4" />
                  <span>{findResult.error}</span>
                </div>
              ) : (
                <>
                  <div className="flex items-center gap-2">
                    <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                    <span className="font-medium">
                      {findResult.dry_run ? '预览结果' : '查找完成'}
                    </span>
                  </div>
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 text-sm">
                    <div className="p-2 rounded bg-background border">
                      <div className="text-muted-foreground text-xs">已处理</div>
                      <div className="font-bold text-lg">{findResult.processed}</div>
                    </div>
                    <div className="p-2 rounded bg-background border">
                      <div className="text-muted-foreground text-xs">已找到</div>
                      <div className="font-bold text-lg text-emerald-600">{findResult.found}</div>
                    </div>
                    <div className="p-2 rounded bg-background border">
                      <div className="text-muted-foreground text-xs">未找到</div>
                      <div className="font-bold text-lg text-amber-600">{findResult.not_found}</div>
                    </div>
                    <div className="p-2 rounded bg-background border">
                      <div className="text-muted-foreground text-xs">剩余待查</div>
                      <div className="font-bold text-lg">{findResult.remaining}</div>
                    </div>
                  </div>

                  {findResult.results && findResult.results.length > 0 && (
                    <div className="space-y-1 max-h-[300px] overflow-y-auto">
                      <div className="text-xs text-muted-foreground font-medium">结果:</div>
                      {findResult.results.map((r, i) => (
                        <div key={i} className="text-sm flex items-center gap-2">
                          {r.michelin_url ? (
                            <CheckCircle2 className="h-3 w-3 text-emerald-500 flex-shrink-0" />
                          ) : (
                            <AlertCircle className="h-3 w-3 text-amber-500 flex-shrink-0" />
                          )}
                          <span className="font-medium truncate">{r.name}</span>
                          <span className="text-muted-foreground text-xs flex-shrink-0">{r.city}</span>
                          {r.michelin_url ? (
                            <a href={r.michelin_url} target="_blank" rel="noreferrer" className="text-xs text-blue-500 hover:underline truncate max-w-[200px]">
                              {r.michelin_url.split('/').pop()}
                            </a>
                          ) : (
                            <span className="text-xs text-muted-foreground">{r.reason}</span>
                          )}
                          <Badge variant="outline" className="text-[10px] flex-shrink-0">分数:{r.score}</Badge>
                        </div>
                      ))}
                    </div>
                  )}
                </>
              )}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
