import { useState, useRef, useEffect } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { Checkbox } from "@/components/ui/checkbox";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { downloadCSV, convertToCSV } from "@/lib/exportUtils";
import {
  Loader2, Search, Brain, Phone, Mail, Globe, ChefHat, Star,
  ExternalLink, Clock, Users, Award, DollarSign, CheckCircle2,
  AlertCircle, Instagram, Facebook, Twitter, RefreshCw, StopCircle,
  Download, Play, ShieldCheck,
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";

const COUNTRIES = [
  { code: "all", label: "全部国家" },
  { code: "Portugal", label: "🇵🇹 葡萄牙" },
  { code: "Spain", label: "🇪🇸 西班牙" },
  { code: "France", label: "🇫🇷 法国" },
  { code: "Italy", label: "🇮🇹 意大利" },
  { code: "Germany", label: "🇩🇪 德国" },
  { code: "United Kingdom", label: "🇬🇧 英国" },
  { code: "Japan", label: "🇯🇵 日本" },
  { code: "United States", label: "🇺🇸 美国" },
];

const MICHELIN_LABELS: Record<string, string> = {
  '3': '⭐⭐⭐ 三星',
  '2': '⭐⭐ 二星',
  '1': '⭐ 一星',
  'bib_gourmand': '🍽️ 必比登',
  'selected': '🌟 入选',
};

const EXPORT_FIELDS = [
  { key: "name", label: "餐厅名称", group: "basic" },
  { key: "name_en", label: "英文名称", group: "basic" },
  { key: "michelin_stars", label: "米其林星级", group: "basic" },
  { key: "city", label: "城市", group: "basic" },
  { key: "country", label: "国家", group: "basic" },
  { key: "address", label: "地址", group: "basic" },
  { key: "phone", label: "餐厅电话", group: "contact" },
  { key: "email", label: "餐厅邮箱", group: "contact" },
  { key: "website_url", label: "官网", group: "contact" },
  { key: "michelin_url", label: "米其林链接", group: "contact" },
  { key: "chef_name", label: "主厨姓名", group: "chef" },
  { key: "chef_email", label: "主厨邮箱", group: "chef" },
  { key: "chef_phone", label: "主厨电话", group: "chef" },
  { key: "price_range", label: "价位区间", group: "detail" },
  { key: "avg_price_per_person", label: "人均消费", group: "detail" },
  { key: "rating", label: "Google评分", group: "detail" },
  { key: "tripadvisor_rating", label: "TripAdvisor评分", group: "detail" },
  { key: "opening_hours", label: "营业时间", group: "detail" },
  { key: "dress_code", label: "着装要求", group: "detail" },
  { key: "year_established", label: "成立年份", group: "detail" },
  { key: "enriched_at", label: "数据完善时间", group: "detail" },
] as const;

const FIELD_GROUPS = [
  { key: "basic", label: "基本信息" },
  { key: "contact", label: "联系方式" },
  { key: "chef", label: "主厨信息" },
  { key: "detail", label: "详细数据" },
];

interface MichelinRestaurant {
  id: string;
  name: string;
  name_en: string | null;
  city: string | null;
  country: string | null;
  michelin_stars: string | null;
  phone: string | null;
  email: string | null;
  website_url: string | null;
  chef_name: string | null;
  chef_email: string | null;
  chef_phone: string | null;
  price_range: string | null;
  avg_price_per_person: string | null;
  enriched_at: string | null;
  enrichment_data: any;
  michelin_url: string | null;
  rating: number | null;
  tripadvisor_rating: number | null;
  opening_hours: any;
  dress_code: string | null;
  social_media: any;
  year_established: string | null;
  address: string;
}

export default function MichelinEnrichmentPanel() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [country, setCountry] = useState("Portugal");
  const [searchTerm, setSearchTerm] = useState("");
  const [enrichFilter, setEnrichFilter] = useState("all");
  const [loading, setLoading] = useState(false);
  const [enrichingId, setEnrichingId] = useState<string | null>(null);
  const [batchLoading, setBatchLoading] = useState(false);
  const [batchProgress, setBatchProgress] = useState({ current: 0, total: 0, succeeded: 0, failed: 0 });
  const [selectedRestaurant, setSelectedRestaurant] = useState<MichelinRestaurant | null>(null);
  const [detailOpen, setDetailOpen] = useState(false);
  const stopBatchRef = useRef(false);

  // Background auto-enrich state
  const [bgEnrichEnabled, setBgEnrichEnabled] = useState(false);
  const [bgProgress, setBgProgress] = useState<{ last_run?: string; succeeded?: number; failed?: number; remaining?: number } | null>(null);
  const [bgLoading, setBgLoading] = useState(false);

  // Website verification state
  const [verifyLoading, setVerifyLoading] = useState(false);
  const [verifyProgress, setVerifyProgress] = useState<{ total: number; changed: number; remaining: number } | null>(null);

  // Background auto-verify state
  const [bgVerifyEnabled, setBgVerifyEnabled] = useState(false);
  const [bgVerifyProgress, setBgVerifyProgress] = useState<{ remaining?: number; changed?: number; last_run?: string; current_restaurant?: string; current_step?: string; current_index?: number; batch_total?: number; status?: string; last_results?: Array<{ name: string; action: string; email?: string }> } | null>(null);
  const [bgVerifyLoading, setBgVerifyLoading] = useState(false);

  // Poll background enrichment + verify status
  const { data: bgSettings } = useQuery({
    queryKey: ["michelin-bg-enrich-settings"],
    queryFn: async () => {
      const { data } = await supabase
        .from('app_settings')
        .select('key, value')
        .in('key', [
          'michelin_auto_enrich_enabled', 'michelin_auto_enrich_country', 'michelin_auto_enrich_progress', 'michelin_auto_enrich_mode',
          'michelin_auto_verify_enabled', 'michelin_auto_verify_country', 'michelin_auto_verify_progress',
        ]);
      const map: Record<string, string> = {};
      data?.forEach((r: any) => { map[r.key] = r.value; });
      return map;
    },
    refetchInterval: (bgEnrichEnabled || bgVerifyEnabled) ? 5000 : 30000,
  });

  // Sync bg state from settings
  const prevBgEnabled = useRef<boolean | null>(null);
  const prevBgVerifyEnabled = useRef<boolean | null>(null);
  useEffect(() => {
    if (!bgSettings) return;
    const enabled = bgSettings['michelin_auto_enrich_enabled'] === 'true';
    if (prevBgEnabled.current !== enabled) {
      prevBgEnabled.current = enabled;
      setBgEnrichEnabled(enabled);
    }
    const progressStr = bgSettings['michelin_auto_enrich_progress'];
    if (progressStr && progressStr !== '{}') {
      try { setBgProgress(JSON.parse(progressStr)); } catch {}
    }
    // Sync verify state
    const verifyEnabled = bgSettings['michelin_auto_verify_enabled'] === 'true';
    if (prevBgVerifyEnabled.current !== verifyEnabled) {
      prevBgVerifyEnabled.current = verifyEnabled;
      setBgVerifyEnabled(verifyEnabled);
    }
    const verifyProgressStr = bgSettings['michelin_auto_verify_progress'];
    if (verifyProgressStr && verifyProgressStr !== '{}') {
      try { setBgVerifyProgress(JSON.parse(verifyProgressStr)); } catch {}
    }
  }, [bgSettings]);

  // Export field selection
  const [exportFields, setExportFields] = useState<string[]>(
    EXPORT_FIELDS.map(f => f.key)
  );
  const [exportOpen, setExportOpen] = useState(false);

  const { data: restaurants, isLoading } = useQuery({
    queryKey: ["michelin-enrichment", country, searchTerm, enrichFilter],
    queryFn: async () => {
      let query = supabase
        .from('restaurants')
        .select('id, name, name_en, city, country, michelin_stars, phone, email, website_url, chef_name, chef_email, chef_phone, price_range, avg_price_per_person, enriched_at, enrichment_data, michelin_url, rating, address, tripadvisor_rating, opening_hours, dress_code, social_media, year_established')
        .not('michelin_stars', 'is', null)
        .eq('visible', true)
        .order('michelin_stars', { ascending: true })
        .order('name', { ascending: true });

      if (country && country !== 'all') query = query.eq('country', country);
      if (searchTerm) query = query.or(`name.ilike.%${searchTerm}%,name_en.ilike.%${searchTerm}%,city.ilike.%${searchTerm}%`);
      if (enrichFilter === 'enriched') query = query.not('enriched_at', 'is', null);
      if (enrichFilter === 'pending') query = query.is('enriched_at', null);
      if (enrichFilter === 'missing_email') query = query.is('email', null).not('michelin_url', 'is', null);

      const { data, error } = await query.limit(500);
      if (error) throw error;
      return (data as unknown as MichelinRestaurant[]) || [];
    },
  });

  const handleEnrichSingle = async (restaurantId: string) => {
    setLoading(true);
    setEnrichingId(restaurantId);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error("Not authenticated");

      const res = await supabase.functions.invoke("enrich-michelin-restaurant", {
        body: { restaurant_id: restaurantId },
      });

      if (res.error) throw res.error;
      if (!res.data?.success) throw new Error(res.data?.error || 'Enrichment failed');

      toast({ title: "数据修补成功", description: `已获取 ${res.data.enrichment?.chef_name || '餐厅'} 的详细信息` });
      queryClient.invalidateQueries({ queryKey: ["michelin-enrichment"] });

      if (selectedRestaurant?.id === restaurantId) {
        const updated = restaurants?.find(r => r.id === restaurantId);
        if (updated) {
          setSelectedRestaurant({ ...updated, ...res.data.enrichment, enriched_at: new Date().toISOString(), enrichment_data: res.data.enrichment });
        }
      }
    } catch (err: any) {
      toast({ title: "修补失败", description: err.message, variant: "destructive" });
    } finally {
      setLoading(false);
      setEnrichingId(null);
    }
  };

  const handleBatchEnrich = async () => {
    const pendingRestaurants = restaurants?.filter(r => !r.enriched_at) || [];
    if (pendingRestaurants.length === 0) {
      toast({ title: "无待修补数据", description: "当前筛选条件下没有待修补的餐厅" });
      return;
    }

    const batchList = pendingRestaurants.slice(0, 10);
    setBatchLoading(true);
    stopBatchRef.current = false;
    setBatchProgress({ current: 0, total: batchList.length, succeeded: 0, failed: 0 });

    let succeeded = 0;
    let failed = 0;

    for (const restaurant of batchList) {
      if (stopBatchRef.current) break;
      try {
        setEnrichingId(restaurant.id);
        const res = await supabase.functions.invoke("enrich-michelin-restaurant", {
          body: { restaurant_id: restaurant.id },
        });
        if (res.error || !res.data?.success) {
          failed++;
        } else {
          succeeded++;
        }
      } catch {
        failed++;
      }
      setBatchProgress(prev => ({ ...prev, current: prev.current + 1, succeeded, failed }));
      await new Promise(r => setTimeout(r, 1500));
    }

    const stopped = stopBatchRef.current;
    setEnrichingId(null);
    setBatchLoading(false);
    stopBatchRef.current = false;
    setBatchProgress({ current: 0, total: 0, succeeded: 0, failed: 0 });
    queryClient.invalidateQueries({ queryKey: ["michelin-enrichment"] });
    toast({
      title: stopped ? "批量修补已停止" : "批量修补完成",
      description: `成功 ${succeeded}/${batchList.length} 家${failed > 0 ? `，失败 ${failed} 家` : ''}${stopped ? '（手动停止）' : ''}`,
    });
  };

  const handleStopBatch = () => {
    stopBatchRef.current = true;
    toast({ title: "正在停止...", description: "将在当前餐厅处理完成后停止" });
  };


  // ═══ Verify websites from Michelin pages ═══
  const handleVerifyWebsites = async () => {
    setVerifyLoading(true);
    try {
      const { data, error } = await supabase.functions.invoke('verify-michelin-websites', {
        body: { limit: 5, country: country !== 'all' ? country : undefined, dry_run: false },
      });
      if (error) throw error;
      setVerifyProgress({
        total: data.total || 0,
        changed: data.changed_count || 0,
        remaining: data.remaining || 0,
      });
      queryClient.invalidateQueries({ queryKey: ["michelin-enrichment"] });
      toast({
        title: "官网校验完成",
        description: `已校验 ${data.total} 家，修正 ${data.changed_count} 家，剩余 ${data.remaining} 家`,
      });
    } catch (err: any) {
      toast({ title: "校验失败", description: err.message, variant: "destructive" });
    }
    setVerifyLoading(false);
  };

  // ═══ Background auto-enrich: toggle via app_settings ═══
  const handleStartBgEnrich = async (enrichMode: string = 'new') => {
    setBgLoading(true);
    try {
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_enrich_enabled', value: 'true', updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_enrich_country', value: country || 'all', updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_enrich_mode', value: enrichMode, updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_enrich_progress', value: '{}', updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      setBgEnrichEnabled(true);
      queryClient.invalidateQueries({ queryKey: ["michelin-bg-enrich-settings"] });
      const desc = enrichMode === 'refresh' 
        ? "将从米其林指南重新获取所有餐厅的官网和信息，每2分钟处理5家" 
        : "每2分钟自动处理5家，可关闭页面";
      toast({ title: enrichMode === 'refresh' ? "后台刷新官网已启动" : "后台自动补充已启动", description: desc });
    } catch (err: any) {
      toast({ title: "启动失败", description: err.message, variant: "destructive" });
    }
    setBgLoading(false);
  };

  const handleStopBgEnrich = async () => {
    setBgLoading(true);
    try {
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_enrich_enabled', value: 'false', updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      setBgEnrichEnabled(false);
      queryClient.invalidateQueries({ queryKey: ["michelin-bg-enrich-settings"] });
      toast({ title: "后台自动补充已停止" });
    } catch (err: any) {
      toast({ title: "停止失败", description: err.message, variant: "destructive" });
    }
    setBgLoading(false);
  };

  // ═══ Background auto-verify: toggle via app_settings ═══
  const handleStartBgVerify = async () => {
    setBgVerifyLoading(true);
    try {
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_verify_enabled', value: 'true', updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_verify_country', value: country || 'all', updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_verify_progress', value: '{}', updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      setBgVerifyEnabled(true);
      queryClient.invalidateQueries({ queryKey: ["michelin-bg-enrich-settings"] });
      toast({ title: "后台自动校验官网已启动", description: "每2分钟校验5家，验证官网并补充邮箱" });
    } catch (err: any) {
      toast({ title: "启动失败", description: err.message, variant: "destructive" });
    }
    setBgVerifyLoading(false);
  };

  const handleStopBgVerify = async () => {
    setBgVerifyLoading(true);
    try {
      await supabase.from('app_settings').upsert({ key: 'michelin_auto_verify_enabled', value: 'false', updated_at: new Date().toISOString() }, { onConflict: 'key' } as any);
      setBgVerifyEnabled(false);
      queryClient.invalidateQueries({ queryKey: ["michelin-bg-enrich-settings"] });
      toast({ title: "后台自动校验已停止" });
    } catch (err: any) {
      toast({ title: "停止失败", description: err.message, variant: "destructive" });
    }
    setBgVerifyLoading(false);
  };

  const toggleExportField = (key: string) => {
    setExportFields(prev =>
      prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]
    );
  };

  const toggleGroup = (groupKey: string) => {
    const groupFields: string[] = EXPORT_FIELDS.filter(f => f.group === groupKey).map(f => f.key);
    const allSelected = groupFields.every(f => exportFields.includes(f));
    if (allSelected) {
      setExportFields(prev => prev.filter(k => !groupFields.includes(k)));
    } else {
      setExportFields(prev => [...new Set([...prev, ...groupFields])]);
    }
  };

  const handleExport = () => {
    if (!restaurants || restaurants.length === 0 || exportFields.length === 0) {
      toast({ title: "无法导出", description: "没有数据或未选择字段", variant: "destructive" });
      return;
    }

    const headers = exportFields;
    const formatted = restaurants.map(r => {
      const row: Record<string, string> = {};
      for (const key of exportFields) {
        const val = (r as Record<string, any>)[key];
        if (key === 'enriched_at' && val) {
          row[key] = new Date(val).toLocaleString('zh-CN');
        } else if (key === 'michelin_stars' && val) {
          row[key] = MICHELIN_LABELS[val] || val;
        } else {
          row[key] = val != null ? String(val) : "";
        }
      }
      return row;
    });

    const csv = convertToCSV(formatted, headers);
    const suffix = country !== 'all' ? `_${country}` : '';
    const filename = `michelin_restaurants${suffix}_${new Date().toISOString().split("T")[0]}.csv`;
    downloadCSV(csv, filename);
    setExportOpen(false);
    toast({ title: "导出成功", description: `已导出 ${restaurants.length} 条记录，${exportFields.length} 个字段` });
  };

  const openDetail = (restaurant: MichelinRestaurant) => {
    setSelectedRestaurant(restaurant);
    setDetailOpen(true);
  };

  const enrichedCount = restaurants?.filter(r => r.enriched_at).length || 0;
  const totalCount = restaurants?.length || 0;
  const pendingCount = totalCount - enrichedCount;
  const missingEmailCount = restaurants?.filter(r => !r.email && r.michelin_url).length || 0;

  return (
    <>
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Brain className="h-5 w-5" />
            米其林餐厅数据完善
          </CardTitle>
          <CardDescription>
            使用 AI 搜索补全餐厅联系方式、主厨信息、评分、价格等数据
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Filters */}
          <div className="flex flex-wrap items-center gap-3">
            <Select value={country} onValueChange={setCountry}>
              <SelectTrigger className="w-[160px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {COUNTRIES.map(c => (
                  <SelectItem key={c.code} value={c.code}>{c.label}</SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Select value={enrichFilter} onValueChange={setEnrichFilter}>
              <SelectTrigger className="w-[140px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">全部</SelectItem>
                <SelectItem value="enriched">已完善</SelectItem>
                <SelectItem value="pending">待完善</SelectItem>
                <SelectItem value="missing_email">缺少邮箱</SelectItem>
              </SelectContent>
            </Select>
            <div className="relative flex-1 min-w-[200px]">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                className="pl-9"
                placeholder="搜索餐厅名称或城市..."
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          {/* Action buttons */}
          <div className="flex flex-wrap items-center gap-2">
            {/* Batch enrich (10) */}
            {batchLoading ? (
              <Button onClick={handleStopBatch} variant="destructive" size="sm">
                <StopCircle className="h-4 w-4 mr-1" />
                停止 ({batchProgress.current}/{batchProgress.total})
              </Button>
            ) : (
              <Button
                onClick={handleBatchEnrich}
                disabled={loading || bgEnrichEnabled}
                variant="outline"
                size="sm"
              >
                <RefreshCw className="h-4 w-4 mr-1" />
                批量修补 ({Math.min(pendingCount, 10)}家)
              </Button>
            )}


            {bgEnrichEnabled ? (
              <Button onClick={handleStopBgEnrich} variant="destructive" size="sm" disabled={bgLoading}>
                <StopCircle className="h-4 w-4 mr-1" />
                停止后台补充 {bgProgress?.remaining != null ? `(剩余${bgProgress.remaining}家)` : ''}
              </Button>
            ) : (
              <Button
                onClick={() => handleStartBgEnrich('new')}
                disabled={loading || batchLoading || pendingCount === 0 || bgLoading || bgVerifyEnabled}
                size="sm"
                className="bg-emerald-600 hover:bg-emerald-700 text-white"
              >
                <Play className="h-4 w-4 mr-1" />
                后台自动补充 ({pendingCount}家)
              </Button>
            )}

            {/* Verify websites - manual */}
            <Button
              onClick={handleVerifyWebsites}
              disabled={verifyLoading || loading || batchLoading || bgEnrichEnabled || bgVerifyEnabled}
              variant="outline"
              size="sm"
            >
              {verifyLoading ? <Loader2 className="h-4 w-4 mr-1 animate-spin" /> : <ShieldCheck className="h-4 w-4 mr-1" />}
              校验官网 (5家)
              {verifyProgress && verifyProgress.remaining > 0 && (
                <Badge variant="secondary" className="ml-1 text-xs">剩余{verifyProgress.remaining}</Badge>
              )}
            </Button>

            {/* Background auto-verify */}
            {bgVerifyEnabled ? (
              <div className="flex flex-col gap-1">
                <Button onClick={handleStopBgVerify} variant="destructive" size="sm" disabled={bgVerifyLoading}>
                  <StopCircle className="h-4 w-4 mr-1" />
                  停止校验 {bgVerifyProgress?.remaining != null ? `(剩余${bgVerifyProgress.remaining}家)` : ''}
                </Button>
                {bgVerifyProgress?.current_restaurant && (
                  <div className="text-xs text-muted-foreground bg-muted/50 rounded px-2 py-1 max-w-xs">
                    <div className="flex items-center gap-1">
                      {bgVerifyProgress.status === 'running' && <span className="animate-pulse text-amber-500">●</span>}
                      <span className="font-medium truncate">{bgVerifyProgress.current_restaurant}</span>
                      {bgVerifyProgress.current_index && bgVerifyProgress.batch_total && (
                        <span className="text-muted-foreground">({bgVerifyProgress.current_index}/{bgVerifyProgress.batch_total})</span>
                      )}
                    </div>
                    {bgVerifyProgress.current_step && (
                      <div className="text-muted-foreground">{bgVerifyProgress.current_step}</div>
                    )}
                  </div>
                )}
                {bgVerifyProgress?.last_results && bgVerifyProgress.last_results.length > 0 && bgVerifyProgress.status !== 'running' && (
                  <div className="text-xs text-muted-foreground bg-muted/30 rounded px-2 py-1 max-w-xs max-h-24 overflow-y-auto">
                    {bgVerifyProgress.last_results.map((r, i) => (
                      <div key={i} className="flex items-center gap-1">
                        <span className={r.action === 'confirmed_match' || r.action === 'confirmed_no_website' ? 'text-green-500' : r.action === 'error' || r.action === 'scrape_failed' ? 'text-red-500' : 'text-amber-500'}>
                          {r.action === 'confirmed_match' ? '✓' : r.action === 'error' || r.action === 'scrape_failed' ? '✗' : '△'}
                        </span>
                        <span className="truncate">{r.name}</span>
                        {r.email && <span className="text-green-600">📧</span>}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ) : (
              <Button
                onClick={handleStartBgVerify}
                disabled={loading || batchLoading || bgEnrichEnabled || bgVerifyLoading}
                size="sm"
                variant="outline"
              >
                <ShieldCheck className="h-4 w-4 mr-1" />
                后台自动校验官网
                {verifyProgress && verifyProgress.remaining > 0 && (
                  <Badge variant="secondary" className="ml-1 text-xs">{verifyProgress.remaining}家</Badge>
                )}
              </Button>
            )}

            {/* Export with field selection */}
            <Popover open={exportOpen} onOpenChange={setExportOpen}>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" disabled={!restaurants?.length}>
                  <Download className="h-4 w-4 mr-1" />
                  导出数据
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-80" align="start">
                <div className="space-y-3">
                  <div className="font-medium text-sm">选择导出字段</div>
                  {FIELD_GROUPS.map(group => {
                    const groupFields = EXPORT_FIELDS.filter(f => f.group === group.key);
                    const allSelected = groupFields.every(f => exportFields.includes(f.key));
                    const someSelected = groupFields.some(f => exportFields.includes(f.key));
                    return (
                      <div key={group.key} className="space-y-1.5">
                        <div
                          className="flex items-center gap-2 cursor-pointer hover:bg-muted/50 rounded px-1 py-0.5"
                          onClick={() => toggleGroup(group.key)}
                        >
                          <Checkbox
                            checked={allSelected ? true : someSelected ? "indeterminate" : false}
                            className="h-3.5 w-3.5"
                          />
                          <span className="text-xs font-semibold text-muted-foreground uppercase">{group.label}</span>
                        </div>
                        <div className="pl-5 space-y-1">
                          {groupFields.map(field => (
                            <div
                              key={field.key}
                              className="flex items-center gap-2 cursor-pointer hover:bg-muted/50 rounded px-1 py-0.5"
                              onClick={() => toggleExportField(field.key)}
                            >
                              <Checkbox
                                checked={exportFields.includes(field.key)}
                                className="h-3.5 w-3.5"
                              />
                              <span className="text-sm">{field.label}</span>
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                  <Separator />
                  <div className="flex items-center justify-between">
                    <span className="text-xs text-muted-foreground">
                      已选 {exportFields.length}/{EXPORT_FIELDS.length} 字段 · {totalCount} 条记录
                    </span>
                    <Button size="sm" onClick={handleExport} disabled={exportFields.length === 0}>
                      <Download className="h-3 w-3 mr-1" />
                      导出 CSV
                    </Button>
                  </div>
                </div>
              </PopoverContent>
            </Popover>
          </div>

          {/* Stats */}
          <div className="flex gap-3">
            <Badge variant="outline" className="gap-1">
              总计 {totalCount}
            </Badge>
            <Badge variant="secondary" className="gap-1 bg-emerald-500/15 text-emerald-700 border-emerald-500/30">
              <CheckCircle2 className="h-3 w-3" /> 已完善 {enrichedCount}
            </Badge>
            <Badge variant="secondary" className="gap-1 bg-amber-500/15 text-amber-700 border-amber-500/30">
              <AlertCircle className="h-3 w-3" /> 待完善 {pendingCount}
            </Badge>
            <Badge variant="secondary" className="gap-1 bg-blue-500/15 text-blue-700 border-blue-500/30">
              <Mail className="h-3 w-3" /> 缺邮箱 {missingEmailCount}
            </Badge>
            {bgEnrichEnabled && (
              <Badge variant="secondary" className="gap-1 bg-blue-500/15 text-blue-700 border-blue-500/30 animate-pulse">
                <Loader2 className="h-3 w-3 animate-spin" /> 后台补充中... {bgProgress?.remaining != null ? `剩余${bgProgress.remaining}家` : ''}
              </Badge>
            )}
          </div>

          {/* Table */}
          {isLoading ? (
            <div className="flex items-center justify-center py-8">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : (
            <div className="border rounded-lg overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="bg-muted/50">
                    <tr>
                      <th className="text-left p-3 font-medium">餐厅</th>
                      <th className="text-left p-3 font-medium">星级</th>
                      <th className="text-left p-3 font-medium">城市</th>
                      <th className="text-left p-3 font-medium">主厨</th>
                      <th className="text-left p-3 font-medium">联系方式</th>
                      <th className="text-left p-3 font-medium">状态</th>
                      <th className="text-right p-3 font-medium">操作</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {restaurants?.map(r => (
                      <tr key={r.id} className={`hover:bg-muted/30 transition-colors ${enrichingId === r.id ? 'bg-blue-500/5' : ''}`}>
                        <td className="p-3">
                          <div className="font-medium truncate max-w-[200px]">{r.name}</div>
                          {r.name_en && r.name_en !== r.name && (
                            <div className="text-xs text-muted-foreground truncate max-w-[200px]">{r.name_en}</div>
                          )}
                        </td>
                        <td className="p-3">
                          <Badge variant="outline" className="text-[10px] whitespace-nowrap">
                            {MICHELIN_LABELS[r.michelin_stars || ''] || r.michelin_stars}
                          </Badge>
                        </td>
                        <td className="p-3 text-muted-foreground text-xs">{r.city}</td>
                        <td className="p-3">
                          {r.chef_name ? (
                            <span className="text-xs">{r.chef_name}</span>
                          ) : (
                            <span className="text-xs text-muted-foreground">-</span>
                          )}
                        </td>
                        <td className="p-3">
                          <div className="flex gap-1">
                            {r.phone && <Phone className="h-3 w-3 text-emerald-500" />}
                            {r.email && <Mail className="h-3 w-3 text-blue-500" />}
                            {r.website_url && <Globe className="h-3 w-3 text-purple-500" />}
                            {r.chef_name && <ChefHat className="h-3 w-3 text-orange-500" />}
                            {r.price_range && <DollarSign className="h-3 w-3 text-emerald-500" />}
                            {(r.opening_hours || r.dress_code) && <Clock className="h-3 w-3 text-blue-500" />}
                            {!r.phone && !r.email && !r.website_url && !r.chef_name && (
                              <span className="text-xs text-muted-foreground">-</span>
                            )}
                          </div>
                        </td>
                        <td className="p-3">
                          {(() => {
                            const fields = [r.phone, r.email, r.website_url, r.chef_name, r.price_range, r.avg_price_per_person, r.opening_hours, r.dress_code];
                            const filled = fields.filter(Boolean).length;
                            const total = fields.length;
                            if (filled >= 6) return <Badge variant="secondary" className="text-[10px] bg-emerald-500/15 text-emerald-700">完善 {filled}/{total}</Badge>;
                            if (filled >= 3) return <Badge variant="secondary" className="text-[10px] bg-blue-500/15 text-blue-700">部分 {filled}/{total}</Badge>;
                            if (r.enriched_at) return <Badge variant="secondary" className="text-[10px] bg-amber-500/15 text-amber-700">基础 {filled}/{total}</Badge>;
                            return <Badge variant="secondary" className="text-[10px] bg-red-500/15 text-red-700">待完善</Badge>;
                          })()}
                        </td>
                        <td className="p-3 text-right">
                          <div className="flex items-center justify-end gap-1">
                            <Button
                              size="sm"
                              variant="ghost"
                              className="h-7 text-xs"
                              onClick={() => openDetail(r)}
                            >
                              详情
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              className="h-7 text-xs gap-1"
                              onClick={() => handleEnrichSingle(r.id)}
                              disabled={loading || batchLoading || bgEnrichEnabled}
                            >
                              {enrichingId === r.id ? <Loader2 className="h-3 w-3 animate-spin" /> : <Brain className="h-3 w-3" />}
                              修补数据
                            </Button>
                          </div>
                        </td>
                      </tr>
                    ))}
                    {restaurants?.length === 0 && (
                      <tr>
                        <td colSpan={7} className="p-8 text-center text-muted-foreground">
                          没有找到匹配的米其林餐厅
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Detail Dialog */}
      <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
        <DialogContent className="max-w-2xl max-h-[85vh]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <ChefHat className="h-5 w-5" />
              {selectedRestaurant?.name}
              {selectedRestaurant?.michelin_stars && (
                <Badge variant="outline" className="ml-2">
                  {MICHELIN_LABELS[selectedRestaurant.michelin_stars] || selectedRestaurant.michelin_stars}
                </Badge>
              )}
            </DialogTitle>
          </DialogHeader>
          <ScrollArea className="max-h-[65vh] pr-4">
            {selectedRestaurant && <RestaurantDetailContent restaurant={selectedRestaurant} />}
          </ScrollArea>
          <div className="flex justify-end gap-2 pt-2">
            <Button
              variant="outline"
              size="sm"
              onClick={() => selectedRestaurant && handleEnrichSingle(selectedRestaurant.id)}
              disabled={loading}
            >
              {loading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <Brain className="h-4 w-4 mr-1" />}
              {selectedRestaurant?.enriched_at ? '重新获取' : '获取数据'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

function RestaurantDetailContent({ restaurant }: { restaurant: MichelinRestaurant }) {
  const ed = restaurant.enrichment_data || {};
  const sm = restaurant.social_media || ed.social_media;
  const openingHoursText = typeof restaurant.opening_hours === 'object' && restaurant.opening_hours?.text 
    ? restaurant.opening_hours.text 
    : ed.opening_hours_text;

  const InfoRow = ({ icon: Icon, label, value, isLink }: { icon: any; label: string; value?: string | null; isLink?: boolean }) => {
    if (!value) return null;
    return (
      <div className="flex items-start gap-3 py-2">
        <Icon className="h-4 w-4 mt-0.5 text-muted-foreground shrink-0" />
        <div className="min-w-0">
          <div className="text-xs text-muted-foreground">{label}</div>
          {isLink ? (
            <a href={value} target="_blank" rel="noopener noreferrer" className="text-sm text-primary hover:underline break-all flex items-center gap-1">
              {value} <ExternalLink className="h-3 w-3 shrink-0" />
            </a>
          ) : (
            <div className="text-sm break-all">{value}</div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-4">
      {/* Basic Info */}
      <div>
        <h4 className="text-sm font-semibold mb-2 flex items-center gap-2">
          <Globe className="h-4 w-4" /> 餐厅信息
        </h4>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 border rounded-lg p-3 bg-muted/20">
          <InfoRow icon={Phone} label="电话" value={restaurant.phone} />
          <InfoRow icon={Mail} label="邮箱" value={restaurant.email || ed.restaurant_email} />
          <InfoRow icon={Globe} label="官网" value={restaurant.website_url || ed.website_url} isLink />
          <InfoRow icon={ExternalLink} label="米其林指南" value={restaurant.michelin_url || ed.michelin_url} isLink />
          <InfoRow icon={DollarSign} label="价位" value={restaurant.price_range || ed.price_range} />
          <InfoRow icon={DollarSign} label="人均" value={restaurant.avg_price_per_person || ed.avg_price_per_person} />
          <InfoRow icon={Star} label="Google评分" value={restaurant.rating?.toString()} />
          <InfoRow icon={Star} label="TripAdvisor评分" value={restaurant.tripadvisor_rating?.toString()} />
          <InfoRow icon={Clock} label="营业时间" value={openingHoursText} />
          <InfoRow icon={Award} label="着装要求" value={restaurant.dress_code || ed.dress_code} />
          <InfoRow icon={Award} label="成立年份" value={restaurant.year_established || ed.year_established} />
        </div>
      </div>

      <Separator />

      {/* Chef Info */}
      <div>
        <h4 className="text-sm font-semibold mb-2 flex items-center gap-2">
          <ChefHat className="h-4 w-4" /> 主厨信息
        </h4>
        <div className="border rounded-lg p-3 bg-muted/20">
          <InfoRow icon={ChefHat} label="主厨" value={restaurant.chef_name || ed.chef_name} />
          <InfoRow icon={Mail} label="主厨邮箱" value={restaurant.chef_email || ed.chef_email} />
          <InfoRow icon={Phone} label="主厨电话" value={restaurant.chef_phone || ed.chef_phone} />
        </div>
      </div>

      {/* Social Media */}
      {sm && (sm.instagram || sm.facebook || sm.twitter) && (
        <>
          <Separator />
          <div>
            <h4 className="text-sm font-semibold mb-2">社交媒体</h4>
            <div className="border rounded-lg p-3 bg-muted/20">
              <InfoRow icon={Instagram} label="Instagram" value={sm.instagram} isLink={sm.instagram?.startsWith('http')} />
              <InfoRow icon={Facebook} label="Facebook" value={sm.facebook} isLink />
              <InfoRow icon={Twitter} label="Twitter" value={sm.twitter} isLink={sm.twitter?.startsWith('http')} />
            </div>
          </div>
        </>
      )}

      {/* Cuisine & Awards */}
      {(ed.cuisine_types?.length > 0 || ed.awards?.length > 0) && (
        <>
          <Separator />
          <div className="space-y-2">
            {ed.cuisine_types?.length > 0 && (
              <div>
                <span className="text-xs text-muted-foreground">菜系: </span>
                <div className="flex flex-wrap gap-1 mt-1">
                  {ed.cuisine_types.map((c: string, i: number) => (
                    <Badge key={i} variant="outline" className="text-[10px]">{c}</Badge>
                  ))}
                </div>
              </div>
            )}
            {ed.awards?.length > 0 && (
              <div>
                <span className="text-xs text-muted-foreground">其他奖项: </span>
                <div className="flex flex-wrap gap-1 mt-1">
                  {ed.awards.map((a: string, i: number) => (
                    <Badge key={i} variant="secondary" className="text-[10px]">{a}</Badge>
                  ))}
                </div>
              </div>
            )}
          </div>
        </>
      )}

      {/* Summary */}
      {ed.summary && (
        <>
          <Separator />
          <div>
            <h4 className="text-sm font-semibold mb-1">简介</h4>
            <p className="text-sm text-muted-foreground">{ed.summary}</p>
          </div>
        </>
      )}

      {/* Enrichment status */}
      <Separator />
      <div className="text-xs text-muted-foreground">
        {restaurant.enriched_at ? (
          <span className="flex items-center gap-1">
            <CheckCircle2 className="h-3 w-3 text-emerald-500" />
            最后更新: {new Date(restaurant.enriched_at).toLocaleString('zh-CN')}
          </span>
        ) : (
          <span className="flex items-center gap-1">
            <AlertCircle className="h-3 w-3 text-amber-500" />
            尚未获取详细数据，点击"获取数据"按钮开始
          </span>
        )}
      </div>
    </div>
  );
}